import{_ as $,o as s,c as r,a as t,b as e,d as l,w as n,e as a,r as c}from"./app.2ab19930.js";const d={},o=t("h1",{id:"\u6570\u5B66\u5EFA\u6A21",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#\u6570\u5B66\u5EFA\u6A21","aria-hidden":"true"},"#"),e(" \u6570\u5B66\u5EFA\u6A21")],-1),m=t("h2",{id:"\u6570\u5B66\u5EFA\u6A21\u601D\u7EF4\u5BFC\u56FE",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#\u6570\u5B66\u5EFA\u6A21\u601D\u7EF4\u5BFC\u56FE","aria-hidden":"true"},"#"),e(" \u6570\u5B66\u5EFA\u6A21\u601D\u7EF4\u5BFC\u56FE")],-1),_=["src"],h=a('<div class="custom-container tip"><p class="custom-container-title">\u601D\u7EF4\u5BFC\u56FE\u4F7F\u7528\u65B9\u6CD5</p><p>\u8282\u70B9\u652F\u6301\u6536\u7EB3\u4E0E\u5C55\u5F00</p><p>\u9F20\u6807\u4E2D\u952E\u6EDA\u52A8\u653E\u5927\u7F29\u5C0F</p><p>\u9F20\u6807\u5DE6\u952E\u62D6\u52A8\u53EF\u79FB\u52A8\u5BFC\u56FE</p></div><h2 id="\u7EFC\u5408\u8BC4\u4EF7-topsis\u6CD5" tabindex="-1"><a class="header-anchor" href="#\u7EFC\u5408\u8BC4\u4EF7-topsis\u6CD5" aria-hidden="true">#</a> \u7EFC\u5408\u8BC4\u4EF7-TOPSIS\u6CD5</h2><p>TOPSIS\uFF1ATechnique for Order Preference by Similarity to Ideal Solution)\u2014\u2014\u903C\u8FD1\u7406\u60F3\u89E3\u6392\u5E8F\u6CD5\uFF0C\u6216\u79F0\u4F18\u52A3\u89E3\u8DDD\u79BB\u6CD5</p><h3 id="\u5C42\u6B21\u5206\u6790\u6CD5\u7684\u5C40\u9650" tabindex="-1"><a class="header-anchor" href="#\u5C42\u6B21\u5206\u6790\u6CD5\u7684\u5C40\u9650" aria-hidden="true">#</a> \u5C42\u6B21\u5206\u6790\u6CD5\u7684\u5C40\u9650</h3><ol><li><p>\u8BC4\u4EF7\u51B3\u7B56\u5C42\u4E0D\u80FD\u592A\u591A\uFF0C\u5426\u5219n\u5F88\u5927\uFF0C\u5224\u65AD\u77E9\u9635\u548C\u4E00\u81F4\u77E9\u9635\u5DEE\u5F02\u5F88\u5927</p><p>\u5E73\u5747\u968F\u673A\u4E00\u81F4\u6027\u6307\u6807\u4E2Dn\u6700\u5927\u4E3A15</p></li><li><p>\u82E5\u6570\u636E\u5DF2\u77E5\uFF0Ctopsis\u4F1A\u66F4\u52A0\u5BA2\u89C2\uFF0C\u5C42\u6B21\u5206\u6790\u6CD5\u4F1A\u66F4\u52A0\u4E3B\u89C2\uFF0C\u4E00\u822C\u4E0D\u5EFA\u8BAE\u4F7F\u7528</p></li></ol><h3 id="\u6307\u6807\u6B63\u5411\u5316\u2014\u2014\u7EDF\u4E00\u6307\u6807\u7C7B\u578B" tabindex="-1"><a class="header-anchor" href="#\u6307\u6807\u6B63\u5411\u5316\u2014\u2014\u7EDF\u4E00\u6307\u6807\u7C7B\u578B" aria-hidden="true">#</a> \u6307\u6807\u6B63\u5411\u5316\u2014\u2014\u7EDF\u4E00\u6307\u6807\u7C7B\u578B</h3><p>\u5C06\u6240\u6709\u7684\u6307\u6807\u8F6C\u5316\u4E3A\u6781\u5927\u578B\u6307\u6807\u79F0\u4E3A<strong>\u6307\u6807\u6B63\u5411\u5316</strong></p><p><strong>\u5E38\u89C1\u7684\u56DB\u79CD\u6307\u6807</strong></p><table><thead><tr><th style="text-align:center;">\u6307\u6807\u540D\u79F0</th><th style="text-align:center;">\u6307\u6807\u7279\u70B9</th><th style="text-align:center;">\u4F8B\u5B50</th></tr></thead><tbody><tr><td style="text-align:center;">\u6781\u5927\u578B\uFF08\u6548\u76CA\u578B\uFF09\u6307\u6807</td><td style="text-align:center;">\u8D8A\u5927\uFF08\u591A\uFF09\u8D8A\u597D</td><td style="text-align:center;">\u6210\u7EE9\u3001GDP\u589E\u901F\u3001\u4F01\u4E1A\u5229\u6DA6</td></tr><tr><td style="text-align:center;">\u6781\u5C0F\u578B\uFF08\u6210\u672C\u578B\uFF09\u6307\u6807</td><td style="text-align:center;">\u8D8A\u5C0F\uFF08\u5C11\uFF09\u8D8A\u597D</td><td style="text-align:center;">\u8D39\u7528\u3001\u574F\u54C1\u7387\u3001\u6C61\u67D3\u7A0B\u5EA6</td></tr><tr><td style="text-align:center;">\u4E2D\u95F4\u578B\u6307\u6807</td><td style="text-align:center;">\u8D8A\u63A5\u8FD1\u67D0\u4E2A\u503C\u8D8A\u597D</td><td style="text-align:center;">\u6C34\u8D28\u91CF\u8BC4\u4F30\u65F6\u7684PH\u503C</td></tr><tr><td style="text-align:center;">\u533A\u95F4\u578B\u6307\u6807</td><td style="text-align:center;">\u843D\u5728\u67D0\u4E2A\u533A\u95F4\u6700\u597D</td><td style="text-align:center;">\u4F53\u6E29\u3001\u6C34\u4E2D\u690D\u7269\u6027\u8425\u517B\u7269\u91CF</td></tr></tbody></table><hr><ul><li>\u6781\u5C0F\u578B\uFF08\u6210\u672C\u578B\uFF09\u6307\u6807</li></ul><p>\u516C\u5F0F\uFF1A$~{x_i}=max-X$\uFF0C\u82E5\u6240\u6709\u5143\u7D20\u5747\u4E3A\u6B63\u6570\uFF08\u975E\u96F6\uFF09\uFF0C\u4E5F\u53EF\u4EE5\u4F7F\u7528$\\frac{1}{x}$</p><ul><li>\u4E2D\u95F4\u578B\u6307\u6807</li></ul><p>\u6307\u6807\u65E2\u4E0D\u8981\u592A\u5927\uFF0C\u4E5F\u4E0D\u8981\u592A\u5C0F\uFF0C\u53D6\u67D0\u7279\u5B9A\u503C\u6700\u597D</p><p>\u5047\u8BBE${x_i}$\u662F\u4E00\u7EC4\u4E2D\u95F4\u578B\u5E8F\u5217\uFF08\u540E\u540C\uFF0C\u4E0D\u8D58\u8FF0\uFF09\uFF0C\u4E14\u6700\u4F73\u6570\u503C\u4E3A$x_{best}$\uFF0C\u90A3\u4E48\u6B63\u5411\u5316\u516C\u5F0F\u5982\u4E0B\uFF1A</p><p>$$M=max{|x_i-x_{best}|},~{x_i}=1-\\frac{|x_i-x_{best}|}{M}$$</p><h2 id="\u76F8\u5173\u6027\u5206\u6790" tabindex="-1"><a class="header-anchor" href="#\u76F8\u5173\u6027\u5206\u6790" aria-hidden="true">#</a> \u76F8\u5173\u6027\u5206\u6790</h2><ul><li>\u603B\u4F53\u76AE\u5C14\u900A$Pearson$\u76F8\u5173\u7CFB\u6570</li></ul><p>\u5BF9\u4E24\u7EC4\u603B\u4F53\u6570\u636E\uFF1A$X:{X_1,X_2,X_3,\\cdots,X_n}$\u4E0E$Y:{Y_1,Y_2,Y_3,\\cdots,Y_n}$</p><p>\u6839\u636E\u300A\u6982\u7387\u8BBA\u4E0E\u6570\u7406\u7EDF\u8BA1\u300B\u6709\u5173\u77E5\u8BC6\uFF0C\u603B\u4F53\u5747\u503C\uFF1A $$E(X)=\\frac{\\sum_{i=1}^{n} X_i}{n}$$</p><p>$$E(Y)=\\frac{\\sum_{i=1}^{n} Y_i}{n}$$</p><p>\u603B\u4F53\u534F\u65B9\u5DEE\uFF1A $$ \\begin{align*} Cov(X,Y)&amp;=\\frac{\\sum_{i=1}^{n} (X_i-E(X))(Y_i-E(Y))}{n}\\ \\ &amp;=E[(X-E(X))(Y-E(Y))] \\end{align*} $$</p><p>\u4F46\u534F\u65B9\u5DEE\u53D7\u4E24\u53D8\u91CF\u7684\u91CF\u7EB2\u5F71\u54CD\uFF0C\u4E0D\u4FBF\u4E8E\u4F5C\u6BD4\u8F83\uFF0C\u6545\u9700\u8981\u5BF9\u5176\u8FDB\u884C\u6807\u51C6\u5316\uFF0C\u53EF\u5F97\u603B\u4F53$Pearson$\u76F8\u5173\u7CFB\u6570\uFF1A $$\\rho <em>{XY}=\\frac{Cov(X,Y)}{\\sigma_X \\sigma_Y}=\\frac{\\sum</em>{i=1}^{n}\\frac{X_i-E(X)}{\\sigma_X}\\frac{Y_i-E(Y)}{\\sigma_Y}}{n}$$</p><div class="custom-container tip"><p class="custom-container-title">\u4E3A\u4EC0\u4E48\u8FD9\u4E48\u8FDB\u884C\u6807\u51C6\u5316\uFF1F</p><ol><li><p>\u4ECE\u91CF\u7EB2\u4E0A\u8003\u8651\uFF0C$X_i-E(X)$\u7684\u91CF\u7EB2\u4E3A$X$\u7684\u5355\u4F4D$[X]$\uFF0C$Y_i-E(Y)$\u7684\u91CF\u7EB2\u4E3A$Y$\u7684\u5355\u4F4D$[Y]$\uFF0C\u5219\u5206\u5B50$[X_i-E(X)][Y_i-E(Y)]$\u7684\u5355\u4F4D\u4E3A$[X][Y]$\u3002\u5206\u6BCD$\\sigma_X \\sigma_Y$\u7684\u5355\u4F4D\u4E5F\u4E3A$[X][Y]$\uFF0C\u6545\u8D77\u5230\u6D88\u9664\u91CF\u7EB2\u7684\u4F5C\u7528\u3002</p></li><li><p>\u53EF\u7C7B\u6BD4\u6B63\u6001\u5206\u5E03\uFF1A\u82E5$X\\sim {}N(\\mu,\\sigma)$\uFF0C\u5219 $$\\frac{X-\\mu}{\\sigma}\\sim N(0,1)$$ \u540C\u7406\uFF0C$\\frac{X_i-E(X)}{\\sigma_X}\\frac{Y_i-E(Y)}{\\sigma_Y}$\u53EF\u8D77\u5230\u6807\u51C6\u5316\u4F5C\u7528</p></li></ol></div><p>\u800C\u5176\u4E2D\uFF0C $$\\sigma_X=\\sqrt{\\frac{\\sum_{i=1}^{n}(X_i-E(X))^2}{n}}$$</p><p>$$\\sigma_Y=\\sqrt{\\frac{\\sum_{i=1}^{n}(Y_i-E(Y))^2}{n}}$$</p><p>\u96BE\u8BC1\u4F46\u53EF\u4EE5\u8BC1\u660E\uFF1A$|\\rho_{XY}|\\le 1$,\uFF08\u8BC1\u660E\u8FC7\u7A0B\u53EF\u4EE5\u4E0D\u7528\u7BA1\uFF0C\u633A\u590D\u6742\uFF09</p><p>\u4E14\u5F53$Y=aX+b$\uFF08\u5373\uFF1A\u4E3A\u7EBF\u6027\u5173\u7CFB\uFF09\u65F6\uFF0C $$\\rho _{XY}=\\begin{cases}1,&amp;a&gt;0\\-1,&amp;a&lt;0\\end{cases}$$</p><ul><li>\u6837\u672C\u76AE\u5C14\u900A$Pearson$\u76F8\u5173\u7CFB\u6570</li></ul><p>\u5BF9\u4E24\u7EC4\u6837\u672C\u6570\u636E\uFF1A$X:{X_1,X_2,X_3,\\cdots,X_n}$\u4E0E$Y:{Y_1,Y_2,Y_3,\\cdots,Y_n}$</p><p>\u6839\u636E\u300A\u6982\u7387\u8BBA\u4E0E\u6570\u7406\u7EDF\u8BA1\u300B\u6709\u5173\u77E5\u8BC6\uFF0C\u6837\u672C\u5747\u503C\uFF1A $$E(X)=\\frac{\\sum_{i=1}^{n} X_i}{n}$$</p><p>$$E(Y)=\\frac{\\sum_{i=1}^{n} Y_i}{n}$$</p><p>\u6837\u672C\u534F\u65B9\u5DEE\uFF1A $$ \\begin{align*} Cov(X,Y)&amp;=\\frac{\\sum_{i=1}^{n} (X_i-E(X))(Y_i-E(Y))}{\\textbf{n-1}} \\end{align*} $$</p><p>\u6837\u672C$Pearson$\u76F8\u5173\u7CFB\u6570\uFF1A $$r_{XY}=\\frac{Cov(X,Y)}{S_X S_Y}=\\frac{\\sum_{i=1}^{n}\\frac{X_i-E(X)}{S_X}\\frac{Y_i-E(Y)}{S_Y}}{\\textbf{n-1}}$$</p><p>\u5176\u4E2D\uFF0C $$S_X=\\sqrt{\\frac{\\sum_{i=1}^{n}(X_i-E(X))^2}{\\textbf{n-1}}}$$</p><p>$$S_Y=\\sqrt{\\frac{\\sum_{i=1}^{n}(Y_i-E(Y))^2}{\\textbf{n-1}}}$$</p><p>\u53C8\uFF1A$|r_{XY}|\\le 1$,</p><p>\u5F53$Y=aX+b$\u65F6\uFF0C $$r_{XY}=\\begin{cases}1,&amp;a&gt;0\\-1,&amp;a&lt;0\\end{cases}$$</p><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>\u6837\u672C\u76AE\u5C14\u900A\u76F8\u5173\u7CFB\u6570\u4E0E\u603B\u4F53\u76AE\u5C14\u900A\u76F8\u5173\u7CFB\u6570\u7684\u5DEE\u522B\u5728\u4E8E\u76F8\u5173\u7CFB\u6570\uFF0C\u534F\u65B9\u5DEE\uFF0C\u65B9\u5DEE\u7684\u5206\u6BCD\uFF0C\u603B\u4F53\u4E3A$n$\uFF0C\u6837\u672C\u4E3A$n-1$\u3002(\u4E0A\u6587\u4E2D\u5DF2\u6807\u7C97\u663E\u793A\uFF0C\u5177\u4F53\u63A8\u5BFC\u590D\u6742\uFF0C\u6B64\u5904\u4E0D\u505A\u8BB0\u5F55)</p></div><ul><li>$Pearson$\u76F8\u5173\u7CFB\u6570\u7684\u8BEF\u533A</li></ul><div style="text-align:center;"><img alt="math_1" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/math_1.jpg" width="500"></div><p>\u4EE5\u4E0A\u56DB\u56FE\uFF0C\u76F8\u5173\u7CFB\u6570\u5747\u4E3A0.816\uFF0C\u672C\u5E94\u8BE5\u5448\u4E25\u683C\u7EBF\u6027\u76F8\u5173\uFF0C\u4F46\u5374\u4EA7\u751F\u4E0D\u540C\u60C5\u51B5\u3002</p><p><code>\u56FE\u4E00</code>\u2014\u2014\u59D1\u4E14\u5B58\u5728\u4E00\u5B9A\u7EBF\u6027\u76F8\u5173\u5173\u7CFB</p><p><code>\u56FE\u4E8C</code>\u2014\u2014\u4E8C\u6B21\u5173\u7CFB\u4E5F\u53EF\u80FD\u4F7F\u5F97\u76F8\u5173\u7CFB\u6570\u5F88\u5927</p><p><code>\u56FE\u4E09</code>\u2014\u2014\u79BB\u7FA4\u70B9\u5BF9\u76F8\u5173\u7CFB\u6570\u5F71\u54CD\u5927</p><p><code>\u56FE\u56DB</code>\u2014\u2014\u5982\u679C\u4E24\u4E2A\u7F16\u91CF\u7684\u76F8\u5173\u7CFB\u6570\u5F88\u5927\u4E5F\u4E0D\u80FD\u8BF4\u660E\u4E24\u8005\u76F8\u5173\uFF0C\u53EF\u80FD\u5B58\u5728\u5F02\u5E38\u503C\u5F71\u54CD\uFF0C\u82E5\u65E0\u5F02\u5E38\u70B9\uFF0C\u5219$\\rho_{XY}=0$\uFF0C\u5219$X,Y$\u65E0\u5173\u3002</p><div style="text-align:center;"><img alt="math_2" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/math_2.jpg" width="500"></div><p>\u4EE5\u4E0A\u60C5\u51B5\uFF0C\u8868\u660E\u76F8\u5173\u7CFB\u6570\u4E3A0\u65F6\uFF0C\u53EA\u80FD\u8BF4\u4E0D\u662F\u7EBF\u6027\u76F8\u5173\uFF0C\u4F46\u53EF\u80FD\u5B58\u5728\u66F4\u4E3A\u590D\u6742\u7684\u76F8\u5173\u5173\u7CFB</p><div class="custom-container danger"><p class="custom-container-title">\u6CE8\u610F</p><p>\u5728\u8BA1\u7B97$Pearson$\u76F8\u5173\u7CFB\u6570\u4E4B\u524D\uFF0C\u9700\u8981\u753B\u51FA\u6563\u70B9\u56FE\uFF0C\u4EE5\u786E\u5B9A\u4E24\u4E2A\u53D8\u91CF\u4E4B\u95F4\u7B26\u5408\u7EBF\u6027\u76F8\u5173\uFF0C\u8FD9\u6837\uFF0C$Pearson$\u76F8\u5173\u7CFB\u6570\u624D\u6709\u610F\u4E49</p></div><ul><li>\u76F8\u5173\u7CFB\u6570\u7ED3\u8BBA</li></ul><ol><li><text style="color:red;">\u5982\u679C\u4E24\u4E2A\u53D8\u91CF\u672C\u8EAB\u5C31\u662F\u7EBF\u6027\u5173\u7CFB\uFF0C</text>\u90A3\u4E48$Pearson$\u76F8\u5173\u7CFB\u6570\u7EDD\u5BF9\u503C\u5927\u7684\u5C31\u662F\u76F8\u5173\u6027\u5F3A\uFF0C\u5C0F\u7684\u5C31\u662F\u76F8\u5173\u6027\u5F31 </li><li><p>\u5728\u4E0D\u786E\u5B9A\u4E24\u4E2A\u53D8\u91CF\u662F\u4EC0\u4E48\u5173\u7CFB\u7684\u60C5\u51B5\u4E0B\uFF0C\u5373\u4F7F\u7B97\u51FA$Pearson$\u76F8\u5173\u7CFB\u6570\uFF0C\u53D1\u73B0\u5F88\u5927\uFF0C\u4E5F\u4E0D\u80FD\u8BF4\u660E\u90A3\u4E24\u4E2A\u53D8\u91CF\u7EBF\u6027\u76F8\u5173\uFF0C\u751A\u81F3\u4E0D\u80FD\u8BF4\u4ED6\u4EEC\u76F8\u5173\uFF0C\u5FC5\u987B\u5148\u753B\u51FA\u6563\u70B9\u56FE\uFF01</p></li></ol><ul><li>\u63CF\u8FF0\u6027\u7EDF\u8BA1</li></ul>',52),g=a('<ul><li>\u5047\u8BBE\u68C0\u9A8C</li></ul><p>\u4F5C\u7528\uFF1A\u5206\u6790<strong>\u663E\u8457\u6027\u6C34\u5E73</strong></p><p>\u76F8\u5173\u6982\u5FF5\uFF1A</p><table><thead><tr><th style="text-align:center;">\u6982\u5FF5\u540D\u79F0</th><th style="text-align:left;">\u542B\u4E49</th></tr></thead><tbody><tr><td style="text-align:center;">\u539F\u5047\u8BBE</td><td style="text-align:left;">\u4EBA\u4E3A\u5047\u8BBE\u51FA\u7684\u7ED3\u8BBA\uFF0C\u6216\u8005\u8BF4\u9700\u8981\u8BC1\u660E\uFF0C\u7136\u540E\u53BB\u76F8\u4FE1\u7684\u7ED3\u8BBA</td></tr><tr><td style="text-align:center;">\u5907\u62E9\u5047\u8BBE</td><td style="text-align:left;">\u4E0D\u76F8\u4FE1\u7684\u5047\u8BBE\uFF0C\u4E0E\u539F\u5047\u8BBE\u76F8\u53CD</td></tr><tr><td style="text-align:center;">\u663E\u8457\u6027\u6C34\u5E73$\\alpha$</td><td style="text-align:left;">\u6211\u4EEC\u6709\u591A\u5927\u53EF\u80FD\u4E0D\u76F8\u4FE1\u539F\u5047\u8BBE</td></tr><tr><td style="text-align:center;">\u7F6E\u4FE1\u6C34\u5E73$\\beta$</td><td style="text-align:left;">\u6211\u4EEC\u6709\u591A\u5927\u53EF\u80FD\u76F8\u4FE1\u539F\u5047\u8BBE</td></tr></tbody></table><p>\u4F8B\uFF1A\u5C0F\u660E\u79F0\u4F53\u91CD94\u65A4\uFF0C\u4F46\u4E4B\u524D\u90FD\u662F90\u65A4\uFF0C\u8FDB\u884C\u5047\u8BBE\u68C0\u9A8C\uFF0C\u4EE5\u8BF4\u660E\u5C0F\u660E\u662F\u5426\u957F\u80D6\uFF08\u5373\uFF1A94~90\u7684\u53D8\u5316\u662F\u5426\u663E\u8457\uFF09</p><p>\u2460\u786E\u5B9A\u539F\u5047\u8BBE$H_0$\u4E0E\u5907\u62E9\u5047\u8BBE$H_1$</p><p>$H_0$\u4E0E$H_1$\u4E3A\u6070\u597D\u76F8\u53CD\u7684\u4E24\u9762</p><p>\u6211\u4EEC\u8981\u68C0\u9A8C\uFF1A\u8FD9\u4E2A\u6708\u4F53\u91CD\u662F\u5426\u4ECD\u4E3A90\u65A4\uFF08\u6216\u8005\u8BF4\u548C90\u65A4\u4F53\u91CD\u662F\u5426\u6709\u663E\u8457\u5DEE\u5F02\uFF0C\u8BBE\u4F53\u91CD\u4E3AW\uFF09\uFF0C\u5219\uFF1A</p><p>$$\\begin{split} H_0&amp;:W=90\\ H_1&amp;:W\\ne 90\\ \u5373\uFF1AH_1&amp;:\\begin{cases} W&gt;90\\ W&lt;90 \\end{cases} \\end{split}$$</p><p>\u6CE8\uFF1A\u8FD9\u79CD\u68C0\u9A8C\u79F0\u4E4B\u4E3A\u53CC\u4FA7\u68C0\u9A8C</p><p>\u2461\u5728$H_0$\u6210\u7ACB\u7684\u6761\u4EF6\u4E0B\uFF0C\u6839\u636E\u6211\u4EEC\u8981\u68C0\u9A8C\u7684\u91CF\u6784\u9020\u4E00\u4E2A\u7B26\u5408\u67D0\u4E00\u5206\u5E03\u7684\u7EDF\u8BA1\u91CF\uFF08\u7EDF\u8BA1\u91CF\u76F8\u5F53\u4E8E\u6211\u4EEC\u8981\u68C0\u9A8C\u7684\u91CF\u7684\u4E00\u4E2A\u51FD\u6570\uFF0C\u91CC\u9762\u4E0D\u80FD\u542B\u6709\u5176\u4ED6\u53D8\u91CF\uFF09</p><p>$$ \\begin{cases} \u6807\u51C6\u6B63\u6001\u5206\u5E03\\ t\u5206\u5E03\\ F\u5206\u5E03\\ X^2\u5206\u5E03\\ \\end{cases} $$</p><p>\u4F8B\uFF1A\u5728$H_0:W=90$\u6210\u7ACB\u7684\u6761\u4EF6\u4E0B\uFF0C\u8BBE\uFF1A$W\\sim N(90,4)$,\u6807\u51C6\u5316\u540E\u5F97\uFF1A$\\frac{W-90}{2}\\sim N(0,1)$\uFF0C\u8BBE$Z=\\frac{W-90}{2}$</p><p>\u2462\u753B\u51FA\u6982\u7387\u5BC6\u5EA6\u51FD\u6570</p><div style="text-align:center;"><img alt="\u6982\u7387\u5BC6\u5EA6\u51FD\u6570" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/math_3.jpg" width="500"></div><p>\u2463\u7ED9\u51FA\u7F6E\u4FE1\u6C34\u5E73</p><p>\u4F8B\uFF1A\u8BBE\u6211\u4EEC\u670995%\u7684\u53EF\u80FD\uFF0C\u76F8\u4FE1\u539F\u5047\u8BBE\u6210\u7ACB\uFF0C\u5373\uFF1A$\\alpha =5%,\\beta=95%$</p><p>\u5219\u9700\u8981\u6839\u636E\u7F6E\u4FE1\u53EF\u80FD\u8BA1\u7B97\u51FA\u63A5\u53D7\u57DF\uFF0C\u62D2\u7EDD\u57DF\uFF0C\u53EF\u5F97\u4E0B\u56FE\uFF1A</p><div style="text-align:center;"><img alt="\u6982\u7387\u5BC6\u5EA6\u51FD\u6570" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/math_4.jpg" width="500"></div><div class="custom-container tip"><p class="custom-container-title">1.96\u5982\u4F55\u8BA1\u7B97\u5F97\u5230</p><p>\u901A\u8FC7\u67E5\u627E\u6B63\u6001\u5206\u5E03\u8868\u53EF\u5F97\uFF1A \u5BF9\u4E8E$X\\sim N(0,1)$\uFF0C$f(x)=\\frac{1}{\\sqrt{2\\pi}}e^{-\\frac{x^2}{2}}$\uFF0C\u800C\u82E5\u7F6E\u4FE1\u6C34\u5E73\u4E3A95%\uFF0C\u5219\uFF1A $$\\int_{-1.96}^{1.96}\\frac{1}{\\sqrt{2\\pi}}e^{-\\frac{x^2}{2}}dx=0.950004$$ \u5373\uFF1A$[-1.96,1.96]$\u533A\u95F4\u5185\uFF0C\u6982\u7387\u5BC6\u5EA6\u51FD\u6570\u6240\u56F4\u9762\u79EF\u4E3A95%</p></div><p>\u6545\uFF1A$H_0$\u6210\u7ACB\u6761\u4EF6\u4E0B\uFF1A $$P(-1.96\\le z\\le 1.96)=0.95$$</p><p>\u800C\u771F\u5B9E\u60C5\u51B5\u4E0B\uFF1A $$z^*=\\frac{94-90}{2}=2&gt;1.96$$</p><p>\u6240\u4EE52\u843D\u5728\u4E860.05\u7684\u5C0F\u6982\u7387\u5185\uFF0C\u5C0F\u6982\u7387\u4E8B\u4EF6\u53D1\u751F\uFF0C\u5047\u8BBE$H_0$\u4E0D\u6210\u7ACB\u3002</p><p><strong>\u8FDB\u4E00\u6B65\u7406\u89E3\u201C\u7F6E\u4FE1\u6C34\u5E73\u201D\uFF1A</strong></p><p>\u82E5\u6B64\u65F6$\\beta=99%$\uFF0C\u901A\u8FC7\u8BA1\u7B97\u53EF\u5F97\uFF0C\u5728$[-2.58,2.58]$\u533A\u95F4\u5185\uFF0C\u6982\u7387\u5BC6\u5EA6\u51FD\u6570\u6240\u8C13\u9762\u79EF\u4E3A$99%$\uFF0C\u5373\uFF1A\u5F53\u771F\u5B9E\u60C5\u51B5\u4E0B\u7684$z^<em>$ \u6EE1\u8DB3 $-2.58\\le z^</em>\\le 2.58$\u65F6\uFF0C\u8BA4\u4E3A\u539F\u5047\u8BBE\u6210\u7ACB\u3002\u7531\u4E8E2&lt;2.58\uFF0C\u6B64\u65F6\u539F\u5047\u8BBE\u6210\u7ACB\u3002</p><p>\u6240\u4EE5\u7F6E\u4FE1\u6C34\u5E73\u8D8A\u5927\uFF0C\u5047\u8BBE\u8D8A\u5BB9\u6613\u6210\u7ACB\u3002\u5047\u8BBE\u7F6E\u4FE1\u6C34\u5E73\u9AD8\u8FBE100%\uFF0C\u5219\u63A5\u53D7\u57DF\u94FA\u6EE1\u6574\u4E2A\u6982\u7387\u5BC6\u5EA6\u51FD\u6570\uFF0C\u539F\u5047\u8BBE\u5FC5\u5B9A\u6210\u7ACB\u3002</p><p><strong>\u82E5\u4E3A\u5355\u4FA7\u68C0\u9A8C\uFF1F</strong></p><p>\u5047\u8BBE\u5355\u4FA7\u68C0\u9A8C\u7684\u539F\u5047\u8BBE\u4E0E\u5907\u62E9\u5047\u8BBE\u5206\u522B\u662F\uFF1A</p><p>$$\\begin{cases} H_0:W=90\\ H_1:W&lt;90 \\end{cases}$$ \u5219\u6B64\u65F6\u7684\u79EF\u5206\u5E94\u4E3A\uFF1A</p><p>$$\\int_{-\\infty }^{2.33}\\frac{1}{\\sqrt{2\\pi}}e^{-\\frac{x^2}{2}}dx=0.99$$</p><p>\u63A5\u53D7\u57DF\u5982\u4E0B\u56FE\uFF1A</p><div style="text-align:center;"><img alt="math_5" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/math_5.jpg" width="500"></div><p>\u5F53\u771F\u5B9E\u60C5\u51B5\u4E0B$z^*\\le 2.33$\u65F6\uFF0C\u6211\u4EEC\u670999%\u7684\u53EF\u80FD\u76F8\u4FE1\u539F\u5047\u8BBE\u6210\u7ACB\u3002</p><ul><li>\u5BF9\u76F8\u5173\u7CFB\u6570\u8FDB\u884C\u5047\u8BBE\u68C0\u9A8C</li></ul><p>Why\uFF1F\u5BF9\u76F8\u5173\u7CFB\u6570\u7684\u89E3\u91CA\u662F\u4F9D\u8D56\u4E8E\u5177\u4F53\u80CC\u666F\u4E0E\u5E94\u7528\u76EE\u7684\u7684\uFF0C\u5355\u4ECE\u6570\u503C\u89D2\u5EA6\u8FDB\u884C\u4E3B\u89C2\u5224\u65AD\u662F\u4E0D\u51C6\u786E\u7684\uFF0C\u9700\u8981\u4F9D\u8D56\u5047\u8BBE\u68C0\u9A8C\u8FDB\u884C\u663E\u8457\u6027\u68C0\u6D4B\uFF0C\u4EE5\u786E\u8BA4\u7EBF\u6027\u5173\u7CFB\u3002</p><p>\u2460\u6784\u9020\u539F\u5047\u8BBE$H_0$\u4E0E\u5907\u62E9\u5047\u8BBE$H_1$</p><p>\u8BA1\u7B97\u51FA$Pearson$\u76F8\u5173\u7CFB\u6570\u540E\uFF0C\u9700\u8981\u8BA1\u7B97\u5176\u662F\u5426\u663E\u8457\u5730\u5F02\u4E8E0\uFF0C\u6545\u6784\u9020\uFF1A</p><p>$$ \\begin{cases} H_0:r=0\\ H_1:r\\ne 0\\ \\end{cases} $$</p><p>\u2461\u6784\u9020\u670D\u4ECE\u67D0\u5206\u5E03\u7684\u68C0\u9A8C\u91CF</p><p>\u5BF9\u4E8E\u76AE\u5C14\u900A\u76F8\u5173\u7CFB\u6570$r$\u800C\u8A00\uFF0C<strong>\u5728\u4E00\u5B9A\u6761\u4EF6\u4E0B</strong>\uFF0C\u53EF\u4EE5\u6784\u9020\uFF1A $$t=r\\sqrt{\\frac{n-2}{1-r^2}}$$ \u5176\u4E2D\uFF0Cn\u4E3A\u6837\u672C\u91CF\uFF0Ct\u670D\u4ECE\u81EA\u7531\u5EA6\u4E3An-2\u7684t\u5206\u5E03\u3002</p><p>(\u8FD9\u91CC\u7684\u6761\u4EF6\u89C1\u540E\u6587~)</p><div class="custom-container tip"><p class="custom-container-title">\u4F55\u4E3At\u5206\u5E03\uFF1F</p><p>t\u5206\u5E03\uFF1A\u91C7\u6837\u8F83\u5C11\u65F6\uFF0C\u5F97\u51FA\u6709\u7528\u7ED3\u679C\uFF0C\u6240\u4EE5t\u5206\u5E03\u76F8\u5BF9\u4E8E\u6B63\u6001\u5206\u5E03\u5BB9\u9519\u7387\u66F4\u9AD8</p><p>\u5173\u952E\u70B9\uFF1A\u7528\u6837\u672C\u6807\u51C6\u5DEE\u4EE3\u66FF\u6574\u4F53\u6807\u51C6\u5DEE</p><p>\u4F46\u662F\u6837\u672C\u6807\u51C6\u5DEE\u4F1A\u968F\u7740\u6837\u672C\u7684\u9009\u53D6\u800C\u6539\u53D8\uFF0C\u800C\u603B\u4F53\u6807\u51C6\u5DEE\u662F\u4E2A\u5B9A\u503C\uFF0C\u4EE5\u53D8\u91CF\u4EE3\u66FF\u5B9A\u503C\u5FC5\u7136\u9020\u6210\u66F4\u5927\u7684\u4E0D\u786E\u5B9A\u6027\uFF0C\u6545\u91C7\u53D6t\u5206\u5E03\u4EE5\u6D88\u9664\u6B64\u4E0D\u786E\u5B9A\u6027\u3002<strong>\u4E5F\u56E0\u6B64\uFF0C\u5728t\u5206\u5E03\u81EA\u7531\u5EA6(\u6837\u672C\u6570-1\u4E3A\u81EA\u7531\u5EA6)\u8DB3\u591F\u9AD8\u7684\u60C5\u51B5\u4E0B\uFF0Ct\u5206\u5E03\u4F1A\u8D8B\u8FD1\u6B63\u6001\u5206\u5E03\uFF0C\u8FD9\u4E5F\u662F\u4F20\u8BF4\u4E2D\u7684\u201C\u4E2D\u5FC3\u6781\u9650\u5B9A\u7406\u201D</strong>\uFF0C\u4E00\u822C\u8BA4\u4E3A\u6807\u51C6\u5DEE\uFF1E30\u65F6\uFF0Ct\u5206\u5E03\u8FD1\u4F3C\u7B49\u4E8E\u6B63\u6001\u5206\u5E03</p></div><p>\u2462\u753B\u51FA\u6982\u7387\u5BC6\u5EA6\u51FD\u6570</p><div style="text-align:center;"><img alt="math_6" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/math_6.jpg" width="500"></div><p>\u2463\u7ED9\u51FA\u7F6E\u4FE1\u6C34\u5E73</p><p>\u4F8B\uFF1A\u76F8\u5173\u7CFB\u6570\u4E3A0.5\uFF0C\u7F6E\u4FE1\u6C34\u5E73\u4E3A95%\uFF0C\u6837\u672C\u4E3A30\uFF0C\u901A\u8FC7\u67E5\u627Et\u5206\u5E03\u8868\u53EF\u5F97\uFF1A $$\\int_{-2.048}^{2.048} f(t)dt=0.95$$</p><p>\u5373\uFF1A\u4E34\u754C\u503C\u4E3A2.048\u3002</p><p>\u6B64\u65F6\uFF0C\u771F\u5B9E\u60C5\u51B5\u4E0B\uFF0C $$t^<em>=r\\sqrt{\\frac{n-2}{1-r^2}}=0.5</em>\\sqrt{\\frac{28}{1-0.5^2}}=3.055&gt;2.048$$</p><div style="text-align:center;"><img alt="math_7" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/math_7.jpg" width="500"></div><p>\u6545r\u843D\u5728\u62D2\u7EDD\u57DF\u5185\uFF0C\u6545\u6211\u4EEC\u670995%\u7684\u53EF\u80FD\u62D2\u7EDD\u539F\u5047\u8BBE$H_0:r=0$\uFF0C\u5373\uFF1Ar\u663E\u8457\u7684\u4E0D\u7B49\u4E8E0\uFF0C\u7EBF\u6027\u76F8\u5173\u6027\u5F3A\u3002</p><ul><li>\u53E6\u5916\u4E00\u79CD\u65B9\u6CD5\u8FDB\u884C\u5047\u8BBE\u68C0\u9A8C\u2014\u2014P\u503C\u6CD5</li></ul><p>\u65B9\u6CD5\u8BBA\uFF1A</p><p>\u2460\u6784\u9020\u539F\u5047\u8BBE\u4E0E\u5907\u62E9\u5047\u8BBE\uFF0C\u6784\u9020\u5206\u5E03\uFF0C\u753B\u51FA\u6982\u7387\u5BC6\u5EA6\u51FD\u6570\u4E0E\u4E0A\u540C</p><p>\u2461\u8BA1\u7B97\u771F\u5B9E\u60C5\u51B5\u4E0B\u7684$z^*$</p><p>\u5982\u4E0A\u4F8B\u6240\u793A\uFF0C $$t^<em>=r\\sqrt{\\frac{n-2}{1-r^2}}=0.5</em>\\sqrt{\\frac{28}{1-0.5^2}}=3.055$$</p><p>\u2462\u8BA1\u7B97\u6982\u7387\u5BC6\u5EA6\u51FD\u6570\u56FE\u4E2D$[t^*,+\\infty]$\u533A\u95F4\u5185\u56FE\u50CF\u6240\u56F4\u9762\u79EF</p><p>$$P{x\\le t^<em>}=\\int_{t^</em>}^{+\\infty}f(t)dt$$</p><p>\u6BD4\u8F83\u9762\u79EF\u4E0E\u63A5\u53D7\u57DF\u7684\u5927\u5C0F\uFF0C\u53EF\u5F97\u4E0B\u9762\u7ED3\u8BBA\uFF1A</p><details class="custom-container details"><summary>\u7ED3\u8BBA</summary><p>$$\\begin{align} &amp;\u5BF9\u4E8E\u7F6E\u4FE1\u6C34\u5E7390%\u7684\u53CC\u4FA7\u68C0\u9A8C\uFF0C&amp;\u82E52p\\le 0.1\uFF0C\u5373\uFF1Ap\\le 0.05\uFF0C\u5219\u62D2\u7EDD\u539F\u5047\u8BBE\uFF0C\\&amp;\u53CD\u4E4B\uFF0C&amp;\u82E5p\\ge 0.05\uFF0C\u5219\u63A5\u53D7\u539F\u5047\u8BBE\uFF1B\\</p><p>&amp;\u5BF9\u4E8E\u7F6E\u4FE1\u6C34\u5E7395%\u7684\u53CC\u4FA7\u68C0\u9A8C\uFF0C&amp;\u82E52p\\le 0.05\uFF0C\u5373\uFF1Ap\\le 0.025\uFF0C\u5219\u62D2\u7EDD\u539F\u5047\u8BBE\uFF0C\\&amp;\u53CD\u4E4B\uFF0C&amp;\u82E5p\\ge 0.025\uFF0C\u5219\u63A5\u53D7\u539F\u5047\u8BBE\uFF1B\\</p><p>&amp;\u5BF9\u4E8E\u7F6E\u4FE1\u6C34\u5E7399%\u7684\u53CC\u4FA7\u68C0\u9A8C\uFF0C&amp;\u82E52p\\le 0.01\uFF0C\u5373\uFF1Ap\\le 0.005\uFF0C\u5219\u62D2\u7EDD\u539F\u5047\u8BBE\uFF0C\\&amp;\u53CD\u4E4B\uFF0C&amp;\u82E5p\\ge 0.005\uFF0C\u5219\u63A5\u53D7\u539F\u5047\u8BBE\uFF1B\\ \\ &amp;\u5BF9\u4E8E\u7F6E\u4FE1\u6C34\u5E7390%\u7684\u5355\u4FA7\u68C0\u9A8C\uFF0C&amp;\u82E5p\\le 0.1\uFF0C\u5219\u62D2\u7EDD\u539F\u5047\u8BBE\uFF0C\\&amp;\u53CD\u4E4B\uFF0C&amp;\u82E5p\\ge 0.1\uFF0C\u5219\u63A5\u53D7\u539F\u5047\u8BBE\uFF1B\\</p><p>&amp;\u5BF9\u4E8E\u7F6E\u4FE1\u6C34\u5E7395%\u7684\u5355\u4FA7\u68C0\u9A8C\uFF0C&amp;\u82E5p\\le 0.05\uFF0C\u5219\u62D2\u7EDD\u539F\u5047\u8BBE\uFF0C\\&amp;\u53CD\u4E4B\uFF0C&amp;\u82E5p\\ge 0.05\uFF0C\u5219\u63A5\u53D7\u539F\u5047\u8BBE\uFF1B\\</p><p>&amp;\u5BF9\u4E8E\u7F6E\u4FE1\u6C34\u5E7399%\u7684\u5355\u4FA7\u68C0\u9A8C\uFF0C&amp;\u82E5p\\le 0.01\uFF0C\u5219\u62D2\u7EDD\u539F\u5047\u8BBE\uFF0C\\&amp;\u53CD\u4E4B\uFF0C&amp;\u82E5p\\ge 0.99\uFF0C\u5219\u63A5\u53D7\u539F\u5047\u8BBE\uFF1B\\ \\end{align} $$</p></details><p>\u5BF9\u672C\u9898\u800C\u8A00\uFF1A $$P{x\\ge t^*}=\\int_{3.055}^{+\\infty }f(t)dt\\le 0.025$$</p><p>\u62D2\u7EDD\u539F\u5047\u8BBE\uFF0C\u5373\uFF1A\u76F8\u5173\u7CFB\u6570$r$\u663E\u8457\u5730\u4E0D\u7B49\u4E8E0\u3002</p>',61);function u(i,f){const p=c("RouterLink");return s(),r("div",null,[o,m,t("iframe",{src:i.$withBase("/markmap/math.html"),width:"100%",height:"800",frameborder:"0",scrolling:"Yes",leftmargin:"0",topmargin:"0"},`
`,8,_),h,t("p",null,[e("\u5728\u62FF\u5230\u4E00\u7CFB\u5217\u6570\u636E\u8FDB\u884C\u76F8\u5173\u6027\u5206\u6790\u4E4B\u524D\uFF0C\u9700\u8981\u5BF9\u6570\u636E\u8FDB\u884C\u63CF\u8FF0\u6027\u7EDF\u8BA1\uFF0C\u6B64\u65F6\uFF0C\u9700\u8981\u501F\u7528matlab\u4EE3\u7801\uFF0C\u53EF\u89C1"),l(p,{to:"/study/code/matlab.html#matlab%E4%B8%AD%E5%9F%BA%E6%9C%AC%E7%BB%9F%E8%AE%A1%E9%87%8F%E5%87%BD%E6%95%B0%E2%80%94%E2%80%94%E6%8F%8F%E8%BF%B0%E6%80%A7%E7%BB%9F%E8%AE%A1"},{default:n(()=>[e("matlab-\u63CF\u8FF0\u6027\u7EDF\u8BA1")]),_:1})]),g])}var x=$(d,[["render",u],["__file","math_0.html.vue"]]);export{x as default};
